/* Croftly service worker (Prompt 12). Explicit caching split:
 *  - CACHE-FIRST for the app shell  — Next static assets, fonts, images, icons.
 *  - NETWORK-FIRST for live data    — navigations / product pages (farm supply,
 *    boxes, prices, order status). Never served stale: cache is used only as an
 *    offline fallback, and the UI marks offline data via the OfflineBanner.
 *
 * Hand-authored (vanilla, no Workbox) because next-pwa's webpack injection is
 * incompatible with Next.js 16's Turbopack build. PRODUCTION: this can be
 * regenerated by a Workbox build step if/when the toolchain supports it.
 */
const VERSION = "croftly-v1";
const SHELL_CACHE = `${VERSION}-shell`;
const RUNTIME_CACHE = `${VERSION}-runtime`;
const OFFLINE_URL = "/offline.html";
const PRECACHE = [OFFLINE_URL, "/manifest.json", "/icon.svg", "/icon-maskable.svg"];

self.addEventListener("install", (event) => {
  event.waitUntil(caches.open(SHELL_CACHE).then((c) => c.addAll(PRECACHE)).then(() => self.skipWaiting()));
});

self.addEventListener("activate", (event) => {
  event.waitUntil(
    caches
      .keys()
      .then((keys) => Promise.all(keys.filter((k) => !k.startsWith(VERSION)).map((k) => caches.delete(k))))
      .then(() => self.clients.claim())
  );
});

function isStaticAsset(url) {
  return (
    url.pathname.startsWith("/_next/static/") ||
    url.pathname.startsWith("/icon") ||
    /\.(?:woff2?|ttf|otf|png|jpe?g|gif|webp|svg|ico)$/.test(url.pathname)
  );
}

self.addEventListener("fetch", (event) => {
  const { request } = event;
  if (request.method !== "GET") return;

  const url = new URL(request.url);
  if (url.origin !== self.location.origin) return; // let cross-origin pass through

  // App shell: cache-first (stale-while-revalidate) for static assets.
  if (isStaticAsset(url)) {
    event.respondWith(
      caches.open(RUNTIME_CACHE).then(async (cache) => {
        const cached = await cache.match(request);
        const network = fetch(request)
          .then((res) => {
            if (res && res.ok) cache.put(request, res.clone());
            return res;
          })
          .catch(() => cached);
        return cached || network;
      })
    );
    return;
  }

  // Navigations + everything else: network-first, fall back to cache, then the
  // offline page. Keeps live data fresh; only serves cached when truly offline.
  event.respondWith(
    fetch(request)
      .then((res) => {
        if (res && res.ok && request.mode === "navigate") {
          const copy = res.clone();
          caches.open(RUNTIME_CACHE).then((c) => c.put(request, copy));
        }
        return res;
      })
      .catch(async () => {
        const cached = await caches.match(request);
        if (cached) return cached;
        if (request.mode === "navigate") return caches.match(OFFLINE_URL);
        return new Response("", { status: 503, statusText: "Offline" });
      })
  );
});
